    function weather_forecast($city = null, $latitude = null, $longitude = null, $timezone = null, $days = null, $timeout = null)
    {
        // Weather Forecast — live data from Open-Meteo (free, no API key)
        $city = $city ?? '';
        $latitude = $latitude ?? null;
        $longitude = $longitude ?? null;
