        $days = $days ?? 3;
        $timeout = $timeout ?? 15;

        $timeout = max(5, min(30, (int)$timeout));
        $days = max(1, min(7, (int)$days));

        // Helper: fetch JSON
        function wf_fetch($url, $timeout) {
            $ctx = stream_context_create([
