            ]);
            $body = @file_get_contents($url, false, $ctx);
            if ($body === false) return ['error' => error_get_last()['message'] ?? 'fetch failed', 'success' => false];
            $status = 200;
            if (isset($http_response_header)) {
                foreach ($http_response_header as $h) {
                    if (preg_match('#^HTTP/\d+\.\d+ (\d+)#', $h, $m)) { $status = (int)$m[1]; break; }
                }
            }
            $data = @json_decode($body, true);
            if ($data === null) return ['error' => 'Invalid JSON', 'status' => $status, 'success' => false];
            return ['data' => $data, 'status' => $status, 'success' => true];
        }

        // Resolve coordinates
        $lat = null;
        $lon = null;

        if (!empty($city)) {
            $geo = wf_fetch('https://geocoding-api.open-meteo.com/v1/search?name=' . urlencode($city) . '&count=5&language=en&format=json', $timeout);
            if (!$geo['success']) return ['error' => 'Geocoding failed: ' . ($geo['error'] ?? 'API error'), 'success' => false];
            if (!isset($geo['data']['results']) || empty($geo['data']['results'])) {
                return ['error' => "City not found: '$city'. Try a different spelling or use lat/lon.", 'success' => false];
            }
            $result = $geo['data']['results'][0];
            $lat = $result['latitude'];
            $lon = $result['longitude'];
            $city_name = $result['name'];
            $country = $result['country'] ?? '';
            $admin1 = $result['admin1'] ?? '';
            $feature = [
                'name' => $city_name,
                'country' => $country,
                'region' => $admin1,
                'elevation' => $result['elevation'] ?? null,
