            95=>'⛈️',96=>'⛈️',99=>'⛈️'];

        // Current conditions
        $current = $d['current'] ?? [];
        $current_units = $d['current_units'] ?? [];
        $cc = [];
        if (!empty($current)) {
            $wc = $current['weather_code'] ?? null;
            $cc = [
                'temperature' => $current['temperature_2m'] . $current_units['temperature_2m'] ?? '°C',
                'feels_like' => $current['apparent_temperature'] . $current_units['apparent_temperature'] ?? '°C',
                'humidity' => $current['relative_humidity_2m'] . $current_units['relative_humidity_2m'] ?? '%',
